      <button onClick={() => setMenuOpen(!menuOpen)} style={{ display: "none", background: "none", border: "1px solid rgba(0,212,255,0.3)", borderRadius: 6, padding: "6px 10px", cursor: "pointer", color: CYAN, fontSize: "1.2rem" }} className="hamburger">☰</button>

      {/* Mobile menu */}
