        <div style={{ fontSize: "0.7rem", color: "rgba(232,244,255,0.38)", letterSpacing: "2px", textTransform: "uppercase", marginBottom: "0.9rem", fontFamily: "'Share Tech Mono',monospace" }}>{tag}</div>
